tool.command:
exec 3>&1 4>&2;
exec > enzywizard.log 2>&1;

#set $mut_clean_name = $mut_clean_report_path.element_identifier
mkdir -p wt_input mut_input &&
unzip -q '$wt_input_zip' -d wt_input &&
unzip -q '$mut_input_zip' -d mut_input &&
ln -sf '$mut_clean_report_path' 'wt_input/$mut_clean_name' &&
if command -v enzywizard-mut-integrate >/dev/null 2>&1; then
    enzywizard-mut-integrate -i 'wt_input/$mut_clean_name' -w wt_input -m mut_input -wo wt_output -mo mut_output $advanced.strict;
elif command -v enzywizard-mut_integrate >/dev/null 2>&1; then
    enzywizard-mut_integrate -i 'wt_input/$mut_clean_name' -w wt_input -m mut_input -wo wt_output -mo mut_output $advanced.strict;
else
    python -m enzywizard_mut_integrate.cli -i 'wt_input/$mut_clean_name' -w wt_input -m mut_input -wo wt_output -mo mut_output $advanced.strict;
fi;
status=\$?;
echo "---- files in Galaxy job working directory ----" >&4;
find . -maxdepth 5 -type f | sort >&4;
if [ "\$status" -ne 0 ]; then cat enzywizard.log >&4; exit "\$status"; fi;
if ! find wt_output mut_output -maxdepth 2 -type f -name '*.json' | grep -q .; then echo "No EnzyWizard Mut Integrate output JSON files were produced." >&4; cat enzywizard.log >&4; [ -f log.txt ] && cat log.txt >&4; exit 1; fi;
